import sys
from collections import deque

def solve():
    input_data = sys.stdin.buffer.read().split()
    idx = 0
    t = int(input_data[idx]); idx += 1
    for _ in range(t):
        n, m = int(input_data[idx]), int(input_data[idx+1]); idx += 2
        grid = []
        lab = None
        for i in range(n):
            row = input_data[idx].decode(); idx += 1
            grid.append(list(row))
            for j in range(len(row)):
                if row[j] == 'L':
                    lab = (i, j)

        dirs = [(-1,0),(1,0),(0,-1),(0,1)]  # up, down, left, right
        good = [[False]*m for _ in range(n)]
        need = [[[0]*4 for _ in range(m)] for _ in range(n)]
        total = [[[0]*4 for _ in range(m)] for _ in range(n)]

        for i in range(n):
            for j in range(m):
                if grid[i][j] == '#': continue
                for c in range(4):
                    cnt = 0
                    for d in range(4):
                        if d == c: continue
                        ni, nj = i+dirs[d][0], j+dirs[d][1]
                        if 0<=ni<n and 0<=nj<m and grid[ni][nj]!='#':
                            cnt += 1
                    need[i][j][c] = cnt
                    total[i][j][c] = cnt

        queue = deque()
        li, lj = lab
        good[li][lj] = True
        queue.append((li, lj))

        while queue:
            y, x = queue.popleft()
            for d in range(4):
                ni, nj = y+dirs[d][0], x+dirs[d][1]
                if 0<=ni<n and 0<=nj<m and grid[ni][nj]!='#' and not good[ni][nj]:
                    for c in range(4):
                        if c == d: continue
                        need[ni][nj][c] -= 1
                        if need[ni][nj][c] == 0 and total[ni][nj][c] > 0:
                            good[ni][nj] = True
                            queue.append((ni, nj))
                            break

        out = []
        for i in range(n):
            for j in range(m):
                if grid[i][j] == '.' and good[i][j]:
                    grid[i][j] = '+'
            out.append(''.join(grid[i]))
        print('\n'.join(out))

solve()

